public int[] closestFactors(int num) {
    int factor1 = (int) Math.sqrt(num + 2);
    while (true) {
        int factor2 = (num + 2) / factor1;
        if (factor1 * factor2 == num + 2) {
            return new int[] {factor1, factor2};
        }
        factor2 = (num + 1) / factor1;
        if (factor1 * factor2 == num + 1) {
            return new int[] {factor1, factor2};
        }
        factor1--;
    }
}
